,menu.id as menu_id1 ,menu.name as menu_name1 ,menu.menu_icon as menu_menu_icon1 ,menu.index_page as menu_index_page1 ,menu.create_time as menu_create_time1 ,child_menu.id as child_menu_id1 ,child_menu.name as child_menu_name1 ,child_menu.menu_icon as child_menu_menu_icon1 ,child_menu.menu_href as child_menu_menu_href1 ,child_menu.index_page as child_menu_index_page1 ,child_menu.menu_id as child_menu_menu_id1 ,child_menu.create_time as child_menu_create_time1 ,sys_user.id as sys_user_id1 ,sys_user.USERNAME as sys_user_USERNAME1 ,sys_user.PASSWORD as sys_user_PASSWORD1 ,sys_user.NAME as sys_user_NAME1 ,sys_user.role_manage_id as sys_user_role_manage_id1 ,sys_user.create_time as sys_user_create_time1 ,sys_user.update_time as sys_user_update_time1 ,sys_user.signature as sys_user_signature1 ,role_manage.id as role_manage_id1 ,role_manage.role_name as role_manage_role_name1 FROM permission_menu su
left join menu menu on menu.id=su.menu_id left join child_menu child_menu on child_menu.id=su.child_menu_id left join sys_user sys_user on sys_user.id=su.sys_user_id left join role_manage role_manage on role_manage.id=su.role_manage_id where 1 = 1 and su.id = #{id} and su.menu_id = #{menu_id} and su.child_menu_id = #{child_menu_id} and su.name_add = #{name_add} and su.name_edit = #{name_edit} and su.name_delete = #{name_delete} and su.name_query = #{name_query} and su.sys_user_id = #{sys_user_id} and su.role_manage_id = #{role_manage_id} and su.create_time = #{create_time}

